import{c as a,Q as i,j as n,m as p}from"./chunks/framework.iD28w_5a.js";const F=JSON.parse('{"title":"003-boot-long-mode-3 · Long Mode","description":"","frontmatter":{"title":"003-boot-long-mode-3 · Long Mode"},"headers":[],"relativePath":"read-through/003-boot-long-mode-3.md","filePath":"read-through/003-boot-long-mode-3.md","lastUpdated":1779686691000}'),e={name:"read-through/003-boot-long-mode-3.md"};function l(t,s,h,r,k,d){return i(),n("div",null,[...s[0]||(s[0]=[p(`<h1 id="_003-3-higher-half-kernel-映射-pml4-511-与-pdpt-510-完整代码讲解" tabindex="-1">003-3 Higher-Half Kernel 映射：PML4[511] 与 PDPT[510] 完整代码讲解 <a class="header-anchor" href="#_003-3-higher-half-kernel-映射-pml4-511-与-pdpt-510-完整代码讲解" aria-label="Permalink to &quot;003-3 Higher-Half Kernel 映射：PML4[511] 与 PDPT[510] 完整代码讲解&quot;">​</a></h1><blockquote><p>标签：x86_64, 长模式, 高半内核, Higher-Half, PML4[511], PDPT[510] 前置：<a href="./003-boot-long-mode-2">003-2 模式切换</a></p></blockquote><h2 id="概览" tabindex="-1">概览 <a class="header-anchor" href="#概览" aria-label="Permalink to &quot;概览&quot;">​</a></h2><p>前两篇我们讲了页表构建的基础部分（恒等映射 0-8MB）和模式切换的五步状态机。</p><p>但如果你仔细看了 <code>boot/common/long_mode.S</code> 中 <code>setup_page_tables</code> 函数的完整代码，</p><p>会发现 <code>ret</code> 指令之前还有一段我们没有讲到的代码——那就是 Higher-Half Kernel 映射。</p><p>这段代码在恒等映射的基础上，</p><p>额外设置了 PML4[511]→PDPT 和 PDPT[510]→PD 的链接，</p><p>把虚拟地址 0xFFFFFFFF80000000 映射到物理地址 0x00000000，</p><p>让内核可以运行在高半地址空间。</p><p>本篇专门讲解这段代码的实现细节，</p><p>包括虚拟地址的二进制拆分、为什么 PDPT 索引是 510 而不是 511、</p><p>以及 x86-64 页表条目必须显式写高 32 位的原因。</p><p>关键设计决策：</p><p>复用已有的 PD 表（PD[0] 已经映射了 0-2MB 物理内存），</p><p>只添加两个链接条目就实现了 Higher-Half 映射；</p><p>显式写高 32 位为 0 以确保页表条目在 64 位视角下完全合法。</p><h2 id="higher-half-的动机" tabindex="-1">Higher-Half 的动机 <a class="header-anchor" href="#higher-half-的动机" aria-label="Permalink to &quot;Higher-Half 的动机&quot;">​</a></h2><p>操作系统的内核通常运行在虚拟地址空间的高地址区域，把低地址区域留给用户进程。</p><p>Linux 就是这么做的——内核映射在 0xFFFFFFFF80000000 以上</p><p>（或者 0xFFFF888000000000 的直接映射区）。</p><p>这样做的好处是用户空间和内核空间有清晰的分界线，用户程序不会意外访问内核内存。</p><p>Cinux 从一开始就瞄准了这个设计。</p><p>内核被加载到物理地址 0x20000（在第一个 2MB 大页范围内），</p><p>但它的入口点被设定为 0xFFFFFFFF80020000——</p><p>也就是说，内核代码期望运行在虚拟地址 0xFFFFFFFF80020000 上。</p><p>为了在 Bootloader 阶段就让这个地址可用，我们需要在页表中建立 Higher-Half 映射。</p><h2 id="虚拟地址的二进制拆分" tabindex="-1">虚拟地址的二进制拆分 <a class="header-anchor" href="#虚拟地址的二进制拆分" aria-label="Permalink to &quot;虚拟地址的二进制拆分&quot;">​</a></h2><p>要理解 PML4[511] 和 PDPT[510] 是怎么来的，</p><p>我们必须把虚拟地址 0xFFFFFFFF80000000 拆开来看。</p><p>x86-64 的四级页表使用 48 位有效虚拟地址</p><p>（高 16 位是符号扩展，即 canonical address 要求）。</p><p>48 位被拆分为四段 9 位索引加一段 12 位页内偏移：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>虚拟地址 0xFFFFFFFF80000000 的二进制：</span></span>
<span class="line"><span>0xFFFFFFFF80000000 = 0xFFFF_FFFF_8000_0000</span></span>
<span class="line"><span></span></span>
<span class="line"><span>高 16 位（符号扩展）: 0xFFFF</span></span>
<span class="line"><span>PML4 索引 (bit 47:39):  0x1FF = 511 (全1)</span></span>
<span class="line"><span>PDPT 索引 (bit 38:30):  0x1FE = 510 (注意！不是 511)</span></span>
<span class="line"><span>PD 索引   (bit 29:21):  0x000 = 0</span></span>
<span class="line"><span>PT 索引   (bit 20:12):  0x000 = 0</span></span>
<span class="line"><span>页内偏移  (bit 11:0):   0x000 = 0</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>PDPT 索引为什么是 510 而不是 511？关键在于 bit 30。</p><p>0x80000000 在 bit 38:30 的范围是：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>0x80000000 的二进制展开（关注 bit 30）：</span></span>
<span class="line"><span>bit 38 = 1, bit 37 = 1, ..., bit 31 = 1, bit 30 = 0</span></span>
<span class="line"><span>PDPT 索引 = 1 1111 1110 = 0x1FE = 510</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>所以 PDPT 索引是 510。这一点非常反直觉——</p><p>你可能以为 PML4 是最后一条（511），那 PDPT 也应该是最后一条（511），</p><p>但实际上 0x80000000 这个地址在 PDPT 索引上 bit 30 为 0，导致索引是 510 而不是 511。</p><p>如果错误地把 PDPT[511] 设成指向 PD，</p><p>对应的虚拟地址会是 0xFFFFFFFFC0000000 而不是 0xFFFFFFFF80000000——差了整整 1GB。</p><h2 id="代码实现" tabindex="-1">代码实现 <a class="header-anchor" href="#代码实现" aria-label="Permalink to &quot;代码实现&quot;">​</a></h2><h3 id="pml4-511-→-pdpt" tabindex="-1">PML4[511] → PDPT <a class="header-anchor" href="#pml4-511-→-pdpt" aria-label="Permalink to &quot;PML4[511] → PDPT&quot;">​</a></h3><div class="language-asm vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    // PML4[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">511</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] -&gt; PDPT (same as PML4[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">])</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    movl $PDPT_PHYS_ADDR, %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">eax</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">       // [imm-&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">eax</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] PDPT physical address</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    orl $0x03, %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">eax</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">                   // [imm-&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">eax</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> present+writable </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">flags</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    movl %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">eax</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, PML4_PHYS_ADDR + (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">511</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> * </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)  // PML4[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">511</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] low </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">32</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> bits</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    movl </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">$0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, PML4_PHYS_ADDR + (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">511</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> * </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) + </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">4</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  // PML4[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">511</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] high </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">32</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> bits = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>PML4[511] 的偏移是 PML4_PHYS_ADDR + (511 * 8) = 0x1000 + 4088 = 0x1FF8。</p><p>这行代码做的事情和设置 PML4[0] 几乎一样——</p><p>把 PDPT 的物理地址加上 Present+Writable 标志写入条目——</p><p>但有一个关键区别：这里显式地写了高 32 位为 0。</p><p>为什么要显式写高 32 位？</p><p>因为 PML4[511] 是一个&quot;非常用&quot;条目——</p><p>它在页表清零阶段确实被清零了，但前面的恒等映射部分用 <code>movl</code> 写 PML4[0] 时，</p><p>高 32 位是靠清零保证的。</p><p>对于 PML4[511] 来说，虽然清零也保证了高 32 位为 0，</p><p>但显式写入是一个更安全、更明确的做法——</p><p>它表明&quot;我确实知道这个条目的高 32 位应该是 0&quot;，而不是依赖一个隐含的前提。</p><p>Intel SDM Vol.3A §4.5 明确要求页表条目中保留位必须为 0，否则会触发 #GP，</p><p>所以显式写 0 是防御性编程。</p><p>PML4[511] 和 PML4[0] 指向同一个 PDPT 表（0x2000）。</p><p>这是有意为之的设计——</p><p>恒等映射和 Higher-Half 映射共享同一套 PDPT 和 PD 表，</p><p>这样只需要在 PDPT 中额外设置一个条目（PDPT[510]）就完成了整个 Higher-Half 映射，</p><p>不需要分配额外的页表页面。</p><h3 id="pdpt-510-→-pd" tabindex="-1">PDPT[510] → PD <a class="header-anchor" href="#pdpt-510-→-pd" aria-label="Permalink to &quot;PDPT[510] → PD&quot;">​</a></h3><div class="language-asm vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    // PDPT[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">510</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] -&gt; PD (</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">NOT</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 511</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">! </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0x80000000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> has bit </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">30</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    movl $PD_PHYS_ADDR, %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">eax</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">         // [imm-&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">eax</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] PD physical address</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    orl $0x03, %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">eax</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">                   // [imm-&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">eax</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> present+writable </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">flags</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    movl %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">eax</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, PDPT_PHYS_ADDR + (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">510</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> * </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)  // PDPT[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">510</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] low </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">32</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> bits</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    movl </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">$0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, PDPT_PHYS_ADDR + (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">510</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> * </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) + </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">4</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  // PDPT[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">510</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] high </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">32</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> bits = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>PDPT[510] 的偏移是 PDPT_PHYS_ADDR + (510 * 8) = 0x2000 + 4080 = 0x2FE0。</p><p>代码注释特别强调了 &quot;NOT 511&quot;——这个 off-by-one 错误是实际开发中很容易犯的。</p><p>设置完 PDPT[510] 指向 PD 后，Higher-Half 映射的路径就完整了：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>虚拟地址 0xFFFFFFFF80000000</span></span>
<span class="line"><span>    ↓ PML4[511]</span></span>
<span class="line"><span>PDPT @ 0x2000</span></span>
<span class="line"><span>    ↓ PDPT[510]</span></span>
<span class="line"><span>PD @ 0x3000</span></span>
<span class="line"><span>    ↓ PD[0] = 0x83 (2MB page, maps 0x00000000 - 0x001FFFFF)</span></span>
<span class="line"><span>物理地址 0x00000000 - 0x001FFFFF ✓</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>PD[0] 是在恒等映射阶段已经设好的条目（值 0x83，映射 0-2MB 物理内存），</p><p>Higher-Half 映射直接复用了这个条目。</p><p>所以内核的虚拟入口地址 0xFFFFFFFF80020000 会被翻译成物理地址 0x20000</p><p>（0x80000000 落在 PD[0] 映射的 0-2MB 范围内，页内偏移是 0x20000）。</p><h2 id="映射关系总结" tabindex="-1">映射关系总结 <a class="header-anchor" href="#映射关系总结" aria-label="Permalink to &quot;映射关系总结&quot;">​</a></h2><p>完成 Higher-Half 映射后，完整的页表结构是这样的：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PML4 (0x1000):</span></span>
<span class="line"><span>  [0]   = 0x2003 → PDPT @ 0x2000  (恒等映射路径)</span></span>
<span class="line"><span>  [511] = 0x2003 → PDPT @ 0x2000  (Higher-Half 映射路径，共享同一张 PDPT)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>PDPT (0x2000):</span></span>
<span class="line"><span>  [0]   = 0x3003 → PD @ 0x3000    (恒等映射路径)</span></span>
<span class="line"><span>  [510] = 0x3003 → PD @ 0x3000    (Higher-Half 映射路径，共享同一张 PD)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>PD (0x3000):</span></span>
<span class="line"><span>  [0] = 0x83      → 0-2MB         (恒等映射 + Higher-Half 共享)</span></span>
<span class="line"><span>  [1] = 0x200083  → 2-4MB         (恒等映射)</span></span>
<span class="line"><span>  [2] = 0x400083  → 4-6MB         (恒等映射)</span></span>
<span class="line"><span>  [3] = 0x600083  → 6-8MB         (恒等映射)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><p>一个物理页面（PD[0]）可以通过两条不同的路径访问：</p><p>低地址的恒等映射（虚拟地址 0x0-0x1FFFFF）和高地址的 Higher-Half 映射</p><p>（虚拟地址 0xFFFFFFFF80000000-0xFFFFFFFF801FFFFF）。</p><p>这意味着内核代码可以在两种地址下运行——</p><p>在 Bootloader 刚进入 Long Mode 时用恒等映射地址执行，</p><p>后续切换到 Higher-Half 映射后用高地址执行。</p><p>这种双映射的设计在操作系统的早期启动阶段非常常见，</p><p>因为 CPU 在切换页表映射时必须始终有一条&quot;能继续执行&quot;的路径。</p><h2 id="设计决策" tabindex="-1">设计决策 <a class="header-anchor" href="#设计决策" aria-label="Permalink to &quot;设计决策&quot;">​</a></h2><h3 id="决策-共享-pdpt-和-pd-而不是分配独立的页表" tabindex="-1">决策：共享 PDPT 和 PD 而不是分配独立的页表 <a class="header-anchor" href="#决策-共享-pdpt-和-pd-而不是分配独立的页表" aria-label="Permalink to &quot;决策：共享 PDPT 和 PD 而不是分配独立的页表&quot;">​</a></h3><p><strong>问题</strong>: Higher-Half 映射需要一套独立的页表还是可以复用恒等映射的？</p><p><strong>本项目的做法</strong>:</p><p>复用同一张 PDPT 和 PD，只额外设置 PML4[511] 和 PDPT[510] 两个条目。</p><p><strong>备选方案</strong>: 为 Higher-Half 映射分配独立的 PDPT 和 PD 页面。</p><p><strong>为什么不选备选方案</strong>:</p><p>复用页表节省了内存（不需要额外的 8KB 页面），而且代码更简单——</p><p>只需要写两个条目而不是重建整张表。</p><p>共享 PDPT 和 PD 的前提是恒等映射和 Higher-Half 映射指向同一段物理内存（0-2MB），</p><p>这恰好是我们需要的行为——内核加载在物理地址 0x20000，两个映射路径都能访问到它。</p><h3 id="决策-显式写高-32-位为-0" tabindex="-1">决策：显式写高 32 位为 0 <a class="header-anchor" href="#决策-显式写高-32-位为-0" aria-label="Permalink to &quot;决策：显式写高 32 位为 0&quot;">​</a></h3><p><strong>问题</strong>: x86-64 页表条目是 64 位的，但我们在 32 位模式下只能用 <code>movl</code> 写 32 位。高 32 位怎么处理？</p><p><strong>本项目的做法</strong>:</p><p>对于 PML4[511] 和 PDPT[510]，在写低 32 位之后，显式用 <code>movl $0, offset+4</code> 写高 32 位为 0。</p><p><strong>备选方案</strong>: 依赖前面的清零操作——清零已经把高 32 位设为 0 了，不需要再写。</p><p><strong>为什么不选备选方案</strong>:</p><p>虽然依赖清零在功能上是正确的，</p><p>但显式写 0 的好处是代码的意图更清晰——</p><p>读者一眼就能看出&quot;我确实知道高 32 位应该是 0&quot;，而不是需要回头去确认&quot;前面是不是清过零了&quot;。</p><p>Intel SDM 要求页表条目中的保留位必须为 0，</p><p>显式写 0 是对这一要求的直接回应，减少了将来维护代码时的认知负担。</p><p>值得注意的是，PML4[0] 和 PDPT[0] 没有显式写高 32 位——它们依赖清零——</p><p>这是一种历史遗留的不一致性。理想情况下所有条目都应该显式写高 32 位。</p><h2 id="扩展方向" tabindex="-1">扩展方向 <a class="header-anchor" href="#扩展方向" aria-label="Permalink to &quot;扩展方向&quot;">​</a></h2><ul><li><p>用 Higher-Half 映射而非恒等映射执行 <code>long_mode_entry</code> 后的代码：</p><p>需要确保远跳转的目标地址使用正确的映射路径</p></li><li><p>扩展 Higher-Half 映射范围：</p><p>PD[1..3] 已经映射了 2-8MB，</p><p>所以 Higher-Half 映射自然覆盖了 0xFFFFFFFF80200000-0xFFFFFFFF807FFFFF</p></li><li><p>在后续内核中，内核会建立自己的完整 Higher-Half 页表映射，</p><p>不再依赖 Bootloader 的临时页表</p></li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li>Intel SDM Vol.3A §4.5 — 4-Level Paging：PML4/PDPT/PD 层级结构，页表条目格式</li><li>Intel SDM Vol.3A §4.5.1 — Page Size Extensions：2MB 大页的基地址计算</li><li>Intel SDM Vol.3A §10.8.5 — Initializing IA-32e Mode：完整的 Long Mode 初始化步骤</li><li>OSDev Wiki: <a href="https://wiki.osdev.org/Setting_Up_Long_Mode" target="_blank" rel="noreferrer">Setting Up Long Mode</a></li><li>OSDev Wiki: <a href="https://wiki.osdev.org/Higher_Half_Kernel" target="_blank" rel="noreferrer">Higher Half Kernel</a> — Higher-Half 内核设计</li><li>OSDev Wiki: <a href="https://wiki.osdev.org/Paging" target="_blank" rel="noreferrer">Paging</a> — 64 位分页的详细描述</li></ul>`,112)])])}const g=a(e,[["render",l]]);export{F as __pageData,g as default};
